// src/components/WordPredictor.js
import React, { useState, useRef, useCallback, useEffect } from 'react';
import Papa from 'papaparse';
import axios from 'axios';

const BACKEND_URL = 'http://localhost:3001';

export const LANGUAGES = [
  { code: 'fr', label: 'Français', flag: '🇫🇷' },
  { code: 'en', label: 'English',  flag: '🇬🇧' },
  { code: 'it', label: 'Italiano', flag: '🇮🇹' },
  { code: 'es', label: 'Español',  flag: '🇪🇸' },
  { code: 'de', label: 'Deutsch',  flag: '🇩🇪' },
  { code: 'ar', label: 'العربية',  flag: '🇹🇳' },
];

// Cache CSV
let csvSymbols = null;
let csvLoading = false;
let csvCallbacks = [];

function loadCSV(cb) {
  if (csvSymbols) { cb(csvSymbols); return; }
  csvCallbacks.push(cb);
  if (csvLoading) return;
  csvLoading = true;
  Papa.parse('/symbol-info.csv', {
    download: true,
    header: true,
    skipEmptyLines: true,
    complete: ({ data }) => {
      csvSymbols = data.filter(r => r['symbol-en']?.trim());
      csvCallbacks.forEach(fn => fn(csvSymbols));
      csvCallbacks = [];
    },
    error: () => {
      csvSymbols = [];
      csvCallbacks.forEach(fn => fn([]));
      csvCallbacks = [];
    },
  });
}

function findSymbol(symbols, word) {
  if (!word || symbols.length === 0) return null;
  const q = word.toLowerCase().trim();

  return (
    symbols.find(s => s['symbol-fr']?.toLowerCase().trim() === q) ||
    symbols.find(s => s['symbol-en']?.toLowerCase().trim() === q) ||
    symbols.find(s => s['symbol-fr']?.toLowerCase().trim().startsWith(q)) ||
    symbols.find(s => s['symbol-en']?.toLowerCase().trim().startsWith(q)) ||
    symbols.find(s => s['tags']?.toLowerCase().includes(q)) ||
    null
  );
}

function SymbolImage({ symbol, label }) {
  const [failed, setFailed] = useState(false);
  useEffect(() => setFailed(false), [symbol]);

  if (!symbol) return <span style={styles.noSymbol}>?</span>;

  const symbolEn = symbol['symbol-en']?.trim();
  const imgUrl = `/EN-symbols/${symbolEn}.svg`;

  return (
    <div style={styles.symbolInner}>
      {!failed ? (
        <img src={imgUrl} alt={label} style={styles.symbolImg} onError={() => setFailed(true)} />
      ) : (
        <span style={styles.noSymbol}>?</span>
      )}
      <span style={styles.symbolLabel}>{label}</span>
    </div>
  );
}

export default function WordPredictor({ 
  fullText, 
  lastWord, 
  cursorBounds, 
  lang, 
  onSelectWord,
  onReplaceText   // ← Important pour appliquer la correction
}) {
  const [words, setWords] = useState([]);
  const [visible, setVisible] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [hoveredIdx, setHoveredIdx] = useState(null);
  const [symbols, setSymbols] = useState([]);

  // États Correction
  const [correctedText, setCorrectedText] = useState('');
  const [showCorrection, setShowCorrection] = useState(false);
  const [isCorrecting, setIsCorrecting] = useState(false);

  const abortRef = useRef(null);
  const debounceRef = useRef(null);

  useEffect(() => { loadCSV(data => setSymbols(data)); }, []);
  useEffect(() => { setHoveredIdx(null); }, [words]);

  // Prédiction des mots
  const fetchPredictions = useCallback(async (text, forcedLang) => {
    if (abortRef.current) abortRef.current.abort();
    abortRef.current = new AbortController();

    setLoading(true);
    setError(null);

    try {
      const res = await axios.post(`${BACKEND_URL}/predictions`, {
        fullText: text.trim(),
        lang: forcedLang || null,
      }, { signal: abortRef.current.signal });

      const cleaned = res.data.filter(w => typeof w === 'string' && w.length > 0 && w.length < 40).slice(0, 8);
      setWords(cleaned);
    } catch (err) {
      if (err.name === 'AbortError') return;
      setError('Erreur de connexion au backend');
      setWords([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (!fullText || fullText.trim().length < 2) {
      setWords([]);
      setVisible(false);
      return;
    }
    setVisible(true);
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => fetchPredictions(fullText.trim(), lang), 350);
    return () => clearTimeout(debounceRef.current);
  }, [fullText, lang, fetchPredictions]);

  // Correction Grammaticale
  const handleCorrection = async () => {
    if (!fullText?.trim()) return;
    setIsCorrecting(true);
    setError(null);

    try {
      const res = await axios.post(`${BACKEND_URL}/correction`, {
        text: fullText.trim(),
        lang: lang || 'fr'
      });

      setCorrectedText(res.data.correctedText);
      setShowCorrection(true);
    } catch (err) {
      setError("Erreur de correction. Vérifie que Mistral est lancé sur Ollama.");
    } finally {
      setIsCorrecting(false);
    }
  };

  const applyCorrection = () => {
    if (correctedText && onReplaceText) {
      onReplaceText(correctedText);
      setShowCorrection(false);
      setCorrectedText('');
    }
  };

  if (!visible) return null;

  const top = (cursorBounds?.bottom || 0) + 50;
  const left = Math.min((cursorBounds?.left || 0) + 16, window.innerWidth - 480);

  const currentLang = lang ? LANGUAGES.find(l => l.code === lang) : null;
  const displayWord = hoveredIdx !== null ? words[hoveredIdx] : lastWord;
  const displaySymbol = findSymbol(symbols, displayWord);

  return (
    <div style={{ ...styles.panel, top, left }}>

      <div style={styles.titleBar}>
        <span style={styles.titleText}>Prédictions + Correction</span>
        <span style={styles.modelBadge}>🤖 Mistral</span>
        <span style={styles.langBadge}>
          {currentLang ? `${currentLang.flag} ${currentLang.label}` : '🌐 Auto'}
        </span>
        <button style={styles.closeBtn} onClick={() => setVisible(false)}>✕</button>
      </div>

      <div style={styles.toolbar}>
        {[
          { icon: '🖼️', label: 'Picture' },
          { icon: '📝', label: 'Correction', action: handleCorrection },
          { icon: '📢', label: 'Reading' },
          { icon: '⚙️', label: 'Config' },
        ].map((item, i) => (
          <div
            key={i}
            style={{
              ...styles.toolBtn,
              background: item.label === 'Correction' && isCorrecting ? '#ff9800' : '#e8e8e8',
            }}
            onClick={() => item.action && item.action()}
          >
            <span style={styles.toolIcon}>
              {item.label === 'Correction' && isCorrecting ? '⏳' : item.icon}
            </span>
            <span style={styles.toolLabel}>{item.label}</span>
          </div>
        ))}
      </div>

      <div style={styles.separator} />

      <div style={styles.body}>
        {/* Colonne gauche : Prédictions */}
        <div style={styles.wordList}>
          {loading && [60, 45, 75, 50, 65, 40].map((w, i) => (
            <div key={i} style={styles.skeletonRow}>
              <div style={{ ...styles.skeletonBar, width: `${w}%` }} />
            </div>
          ))}

          {!loading && error && <div style={styles.errorBox}>⚠️ {error}</div>}

          {!loading && !error && words.map((word, i) => (
            <div
              key={i}
              style={{
                ...styles.wordRow,
                background: i === hoveredIdx ? '#c8d8f0' : 'white',
              }}
              onClick={() => onSelectWord(word)}
              onMouseEnter={() => setHoveredIdx(i)}
              onMouseLeave={() => setHoveredIdx(null)}
            >
              {word}
            </div>
          ))}
        </div>

        {/* Colonne droite : Image + Correction en bas */}
        <div style={styles.rightColumn}>
          {/* Image (Pictogramme) */}
          <div style={styles.symbolBox}>
            <SymbolImage symbol={displaySymbol} label={displayWord} />
          </div>

          {/* Zone Correction - Cadre orange en bas */}
          {showCorrection && correctedText && (
            <div style={styles.correctionPanel}>
              <strong>Texte corrigé :</strong>
              <div style={styles.correctedTextBox}>{correctedText}</div>
              <div style={styles.correctionButtons}>
                <button style={styles.applyBtn} onClick={applyCorrection}>
                  Appliquer
                </button>
                <button style={styles.cancelBtn} onClick={() => setShowCorrection(false)}>
                  Annuler
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

